// Script Continued Below
// This Script is provided to show the changes made to UI Actions as part of the updates to all customers to add custom forms for different task types.

// The parts of the script that change visibility settings are commented out when shipped.
// The changes made by this script left many orphaned items in the application
// Part of this script removes the orphaned items.  
//----------------------------------------------------------------------------------------------------------------------------------------------
//----------------------------------------------------------------------------------------------------------------------------------------------
// The part that removes orphaned items WILL ONLY BE RUN ON ENVIRONMENTS INSTALLED FROM THE STORE
// It is IMPORTANT that the orphaned items remain in the product when shipped to remove the old settings from customer systems
//----------------------------------------------------------------------------------------------------------------------------------------------
//----------------------------------------------------------------------------------------------------------------------------------------------
// It will NOT hurt customer environments if the script to remove the orphans is not run
// It is recommended that this fix script that only removes the orphans is run by customers after installing 2.7


// all of these settings should be false to test and true to remove
var modifyVisibility = true;  // this should be true to execute

//----------------------------------------------------------------------------------------------------------------------------------------------
// NOTE: Move these 2 scripts to the top before providing to Gil
//----------------------------------------------------------------------------------------------------------------------------------------------
// this function counts the settings before and after running
count_UI_Action_visibility('before');

// This function is run after Update and NEVER in development or any environment before deployment from the store
// This function will remove the orphan visibiity settings.
// The orphan settings need to stay in the app until deployment at the customer site or the orphans will be deleted and not pushed to the customers
remove_orphan_visibility_settings();

// this function counts the settings before and after running
count_UI_Action_visibility('after');


function remove_orphan_visibility_settings(){
	var countOfDeleteOrphans = 0;
	var grCleanOrphans = new GlideRecord(actionVeiewTableName);

	// delete all orphan rows
	grCleanOrphans.addEncodedQuery('sys_scope=c6b1162d4fc10300303dc3818110c7b1^sys_ui_action.table=' + 
									taskTableName + 
									'^sys_ui_viewISEMPTY^ORsys_ui_actionISEMPTY^ORsys_ui_view=^ORsys_ui_action='
									);
	while(grCleanOrphans.next()){
		countOfDeleteOrphans++;
		if(modifyVisibility){
			grCleanOrphans.deleteRecord();	
		}
	}
	if(modifyVisibility){
		gs.info('2.7 - this fix script removed many UI Action Visbility Settings leaving them orphaned ' +
				' - Number of Orphaned settings deleted: ' + countOfDeleteOrphans + 
				' for a Tasker 2.6 to 2.7 the counts should be - Deleted Orphans: ?');
	} else {
		gs.info('2.7 - this fix script removed many UI Action Visbility Settings leaving them orphaned changes Counted, but not changed' +
				' - Number of Orphaned settings counted that will be deleted: ' + countOfDeleteOrphans + 
				' for a Tasker 2.6 to 2.7 the counts should be - Delete Orphans: ?');
	}	
}

function count_UI_Action_visibility(beforeOrAfter){
	var countOfVisibilityActions = 0;
	var gaTaskActionVisibility = new GlideAggregate(actionVeiewTableName);
	gaTaskActionVisibility.addEncodedQuery('sys_scope=c6b1162d4fc10300303dc3818110c7b1^sys_ui_action.table=' + taskTableName);
	gaTaskActionVisibility.addAggregate("COUNT");
	gaTaskActionVisibility.query();
	if(gaTaskActionVisibility.next()){
		countOfVisibilityActions = gaTaskActionVisibility.getAggregate("COUNT");
	}

	if(beforeOrAfter == 'before'){
		gs.info('2.7 - UI Action - Visbility Settings - All UI Visibility Settings on Task Table: ' + countOfVisibilityActions + ' for a Tasker 2.6 to 2.7 upgrade Before Changes, this should return 102.');		
	} else{
		gs.info('2.7 - UI Action - Visbility Settings - All UI Visibility Settings on Task Table: ' + countOfVisibilityActions + ' for a Tasker 2.6 to 2.7 upgrade After Changes, this should return ?.');
	}


	var gaTaskModalActionVisibility = new GlideAggregate(actionVeiewTableName);
	var countOfModalVisibilityActions = 0;
	gaTaskModalActionVisibility.addEncodedQuery('sys_scope=c6b1162d4fc10300303dc3818110c7b1^sys_ui_action.table=' + taskTableName +
												'^sys_ui_view!=Default view^sys_ui_view!=36a6a1acdb8bb740c448d1c2ca96191f^sys_ui_view!=ec2daaf9d7523100a9ad1e173e24d4ea^visibility=include');

	gaTaskModalActionVisibility.addAggregate("COUNT");
	gaTaskModalActionVisibility.query();
	if(gaTaskModalActionVisibility.next()){
		countOfModalVisibilityActions = gaTaskModalActionVisibility.getAggregate("COUNT");
	}

	if(beforeOrAfter == 'before'){
		gs.info('2.7 - UI Action - Visbility Settings - Modal/Include UI Visibility Settings on Task Table: ' + countOfModalVisibilityActions + ' for a Tasker 2.6 to 2.7 upgrade Before Changes, this should return 14.');
	} else {
		gs.info('2.7 - UI Action - Visbility Settings - Modal/Include UI Visibility Settings on Task Table: ' + countOfModalVisibilityActions + ' for a Tasker 2.6 to 2.7 upgrade After Changes, this should return 14.');
	}
}

