function updateAll_UI_Action_visibility(){
	// Use the Service Portal as the base to find all buttons that need to be excluded from all Modals
	add_Exclude_for_Each_Standard_Button_to_Each_Modal();
	// remove all of the includes for the standard buttons from the standard views
	remove_include_for_Each_Standard_Button_on_non_Modal_views();
	// switch the settings for the update buttons for both Modal and Standard forms
	swap_update_action_visibility_settings();
	// remove delete button from modals
	hide_delete_buttons_on_modals();
}


function add_Exclude_for_Each_Standard_Button_to_Each_Modal(){
	var countOfStandardButtons = 0;
	var countOfExcludedButtons = 0;
	var grModalExclude = new GlideRecord(actionVeiewTableName);
	var grStandardButtons = new GlideRecord(actionVeiewTableName);
	grStandardButtons.addEncodedQuery( 'sys_scope=c6b1162d4fc10300303dc3818110c7b1^sys_ui_action.table=' + taskTableName + '^sys_ui_view.name=sp^visibility=include');
	grStandardButtons.query();
	while(grStandardButtons.next()){
		countOfStandardButtons++;
		for(i= 0; i<modalViews.length; i++){
			countOfExcludedButtons++;
			if(modifyVisibility && !checkExists(modalViews[i],grStandardButtons.sys_ui_action,'exclude')){
				// Make sure this has not already been added
				grModalExclude.initialize();
				grModalExclude.sys_ui_action = grStandardButtons.sys_ui_action;
				grModalExclude.sys_ui_view = modalViews[i];
				grModalExclude.visibility = 'exclude';
				grModalExclude.insert();
			}
		}

	}
	if(modifyVisibility){
		gs.info('2.7 - UI Action - Visbility Settings - Exclude visibility added to Modals for Standard Buttons' +
				' - Number of Standard Buttons Found: ' + countOfStandardButtons + 
				' - Number of Modal Forms: ' + modalViews.length + 
				' - Number of Standard Buttons Excluded from Modals: ' + countOfExcludedButtons + 
				' for a Tasker 2.6 to 2.7 the counts should be - Standard Buttons: 28, Modal Forms: 10, Exclude Visibility Added: 280.');
	} else {
		gs.info('2.7 - UI Action - Visbility Settings - Exclude visibility Count, but not changed for Excluding Standard Buttons from Modals' +
				' - Number of Standard Buttons Found: ' + countOfStandardButtons + 
				' - Number of Modal Forms: ' + modalViews.length + 
				' - Number of Standard Buttons counted for Exclusion from Modals: ' + countOfExcludedButtons + 
				' for a Tasker 2.6 to 2.7 the counts should be - Standard Buttons: 28, Modal Forms: 10, Exclude Visibility Added: 280.');		
	}
}

function remove_include_for_Each_Standard_Button_on_non_Modal_views(){
	var countOfIncludedStandardButtons = 0;
	var countOfIncludedButtonsRemoved = 0;
	var grStandardButtons = new GlideRecord(actionVeiewTableName);
	grStandardButtons.addEncodedQuery('sys_scope=c6b1162d4fc10300303dc3818110c7b1^sys_ui_action.table=' + 
									taskTableName + '^visibility=include' +
									'^sys_ui_view.name=sp^ORsys_ui_view.title=Default view^ORsys_ui_view.name=Unassigned'
									);
	grStandardButtons.query();
	while(grStandardButtons.next()){
		countOfIncludedStandardButtons++;
		countOfIncludedButtonsRemoved++;
		if(modifyVisibility){
			grStandardButtons.sys_ui_action = '';
			grStandardButtons.sys_ui_view = '';
			grStandardButtons.visibility = '';
			grStandardButtons.update();
		}
	}
	if(modifyVisibility){
		gs.info('2.7 - UI Action - Visbility Settings - Include visibility removed for Standard Buttons from Standard Views' +
				' - Number of Include Visibility for Standard Buttons Found: ' + countOfIncludedStandardButtons + 
				' - Number of Standard Button Include Visibility removed for Standard Buttons: ' + countOfIncludedButtonsRemoved + 
				' for a Tasker 2.6 to 2.7 the counts should be - Include Visibility Standard Buttons: 85.');
	} else {
		gs.info('2.7 - UI Action - Visbility Settings - Include visibility for Standard Buttons on Standard Views Counted, but not changed' +
				' - Number of Include Visibility for Standard Buttons Found: ' + countOfIncludedStandardButtons + 
				' - Number of Standard Button Include Visibility counted for but not removed: ' + countOfIncludedButtonsRemoved + 
				' for a Tasker 2.6 to 2.7 the counts should be - Include Visibility Standard Buttons: 85.');
	}
}

function swap_update_action_visibility_settings(){
	var modalUpdateGUID = '641a0d7a1b74a0103dc8eb96624bcbc5';
	var standardUpdateGUID = '5456488bdb1b5c50dd3d6165ca9619e0';
	var countOfUpdateButtonsRemoved = 0;
	var countOfUpdateButtonsAddedBack = 0;
	var grUpdateAddButtons = new GlideRecord(actionVeiewTableName);
	var grUpdateRemoveButtons = new GlideRecord(actionVeiewTableName);
	grUpdateRemoveButtons.addEncodedQuery('sys_scope=c6b1162d4fc10300303dc3818110c7b1^sys_ui_action.table=' + 
									taskTableName + 
									'^sys_ui_action=' + modalUpdateGUID + '^ORsys_ui_action=' + standardUpdateGUID
									);

	grUpdateRemoveButtons.query();
	while(grUpdateRemoveButtons.next()){
		countOfUpdateButtonsRemoved++;
		// remove all visibility settings from update buttons
		if(modifyVisibility){
			grUpdateRemoveButtons.sys_ui_action = '';
			grUpdateRemoveButtons.sys_ui_view='';
			grUpdateRemoveButtons.update();
		}
	}
	// add back include and exclude on the modal forms
	for(i= 0; i<modalViews.length; i++){
		countOfUpdateButtonsAddedBack++;
		if(modifyVisibility && !checkExists(modalViews[i],modalUpdateGUID,'include')){
			// Make sure this has not already been added
			grUpdateAddButtons.initialize();
			grUpdateAddButtons.sys_ui_action = modalUpdateGUID;
			grUpdateAddButtons.sys_ui_view = modalViews[i];
			grUpdateAddButtons.visibility = 'include';
			grUpdateAddButtons.insert();
		}
		if(modifyVisibility && !checkExists(modalViews[i],standardUpdateGUID,'exclude')){
			// Make sure this has not already been added
			grUpdateAddButtons.initialize();
			grUpdateAddButtons.sys_ui_action = standardUpdateGUID;
			grUpdateAddButtons.sys_ui_view = modalViews[i];
			grUpdateAddButtons.visibility = 'exclude';
			grUpdateAddButtons.insert();
		}			
	}
	if(modifyVisibility){
		gs.info('2.7 - UI Action - Update Visbility Settings - Update Buttons visibility removed and readded from Standard and Modal Forms' +
				' - Number of Update Visibility settings Removed: ' + countOfUpdateButtonsRemoved + 
				' - Number of Update Visibility settings Readded: ' + countOfUpdateButtonsAddedBack + 
				' for a Tasker 2.6 to 2.7 the counts should be - Removed: 6, Readded: 10.');
	} else {
		gs.info('2.7 - UI Action - Update Visbility Settings - Update Buttons visibility changes Counted, but not changed' +
				' - Number of Update Visibility settings counted that will be Removed: ' + countOfUpdateButtonsRemoved + 
				' - Number of Update Visibility settings counted that will be Readded: ' + countOfUpdateButtonsAddedBack + 
				' for a Tasker 2.6 to 2.7 the counts should be - Removed: 6, Readded: 10.');
	}
}

function hide_delete_buttons_on_modals(){
	var deleteGUID = '9e53d1f8db02f01087f2892d139619ed';
	var countOfDeleteHidesAdded = 0;
	var grDeleteHide = new GlideRecord(actionVeiewTableName);

	for(i= 0; i<modalViews.length; i++){
		countOfDeleteHidesAdded++;
		if(modifyVisibility && !checkExists(modalViews[i],deleteGUID,'exclude')){
			// Make sure this has not already been added
			grDeleteHide.initialize();
			grDeleteHide.sys_ui_action = deleteGUID;
			grDeleteHide.sys_ui_view = modalViews[i];
			grDeleteHide.visibility = 'exclude';
			grDeleteHide.insert();
		}
	}
	if(modifyVisibility){
		gs.info('2.7 - UI Action - Delete Visbility Settings - Delete Buttons exclude visibility readded to Modal Forms' +
				' - Number of Delete Exclude Visibility settings Added: ' + countOfDeleteHidesAdded + 
				' for a Tasker 2.6 to 2.7 the counts should be - Delete Excludes Added: 10');
	} else {
		gs.info('2.7 - UI Action - Update Visbility Settings - Update Buttons visibility changes Counted, but not changed' +
				' - Number of Delete Exclude Visibility settings counted that will be Added: ' + countOfDeleteHidesAdded + 
				' for a Tasker 2.6 to 2.7 the counts should be - Delete Excludes Added: 10');
	}	
}

function checkExists(view, action, visibility){
	var answer = false;
	var gaVisExists = new GlideAggregate(actionVeiewTableName);
	var existsQuery ='sys_scope=c6b1162d4fc10300303dc3818110c7b1^sys_ui_action.table=' + taskTableName +
								'^sys_ui_view.name=' + view + '^sys_ui_action=' + action + '^visibility=' + visibility;
	gaVisExists.addEncodedQuery(existsQuery);

	gaVisExists.addAggregate("COUNT");
	gaVisExists.query();
	if(gaVisExists.next()){
		answer = gaVisExists.getAggregate("COUNT") > 0;
	}
	return answer;
}

